+// ---------------------------------------------------------------------------
+// FallbackConfig — configurable parameters
+// ---------------------------------------------------------------------------
+
+/// Configuration for fallback protocol and rate monitoring.
+#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
+pub struct FallbackConfig {
