+    fn build_after(
+        prev: &PolicyCheckpoint,
+        seq: u64,
+        epoch: SecurityEpoch,
+        tick: u64,
+        keys: &[SigningKey],
+        zone: &str,
+    ) -> PolicyCheckpoint {
+        CheckpointBuilder::after(prev, seq, epoch, DeterministicTimestamp(tick), zone)
+            .add_policy_head(make_policy_head(PolicyType::RuntimeExecution, seq + 1))
+            .build(keys)
+            .unwrap()
+    }
