+        CheckpointBuilder::after(prev, seq, epoch, DeterministicTimestamp(tick), zone)
+            .add_policy_head(make_policy_head(
+                PolicyType::RuntimeExecution,
+                seq + 1 + version_offset,
+            ))
+            .build(keys)
+            .unwrap()
+    }
